import { defineConfig } from 'vite'
import react from '@vitejs/plugin-react'

export default defineConfig({
  plugins: [react()],
})

@tailwind base;
@tailwind components;
@tailwind utilities;

:root {
  --color-bg: #111111;
  --color-surface: #1A1A1A;
  --color-primary: #E8400A;
  --color-primary-hover: #FF5A26;
  --color-primary-pressed: #C23508;
  --color-border: #2A2A2A;
}

body {
  background-color: var(--color-bg);
  font-family: 'Inter', sans-serif;
  overflow-x: hidden;
}

.font-display {
  font-family: 'Oswald', sans-serif;
}

/* Subtle film grain overlay / halftone hint at 3-6% opacity */
.bg-grain {
  position: relative;
}
.bg-grain::before {
  content: "";
  position: absolute;
  top: 0; left: 0; right: 0; bottom: 0;
  background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 200 200' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noiseFilter'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.8' numOctaves='3' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noiseFilter)' opacity='0.04'/%3E%3C/svg%3E");
  pointer-events: none;
  z-index: 50;
  opacity: 1;
  mix-blend-mode: overlay;
}

/* Base custom classes to match design system strictness */
@layer components {
  .btn-primary {
    @apply relative inline-flex items-center justify-center bg-signal-core text-white font-display font-bold uppercase tracking-widest text-sm px-8 py-4 hover:bg-signal-bright active:bg-signal-deep transition-all duration-300 rounded-[2px] shadow-[0_0_25px_theme(colors.signal.glow)] hover:shadow-[0_0_40px_theme(colors.signal.glow)] hover:-translate-y-1 overflow-hidden;
  }
  .btn-primary::after {
    content: '';
    @apply absolute top-0 left-0 w-full h-full bg-white opacity-0 transition-opacity duration-300 pointer-events-none;
  }
  .btn-primary:hover::after {
    @apply opacity-10;
  }

  .btn-secondary {
    @apply inline-flex items-center justify-center border border-neutral-700 bg-transparent text-absolute-white font-display uppercase tracking-widest text-sm px-8 py-4 hover:border-signal-core hover:text-signal-core transition-colors duration-200 rounded-[2px];
  }
  .section-padding {
    @apply py-24 md:py-32;
  }
  .eyebrow {
    @apply font-display text-neutral-400 uppercase tracking-[0.14em] text-xs mb-4 block font-semibold;
  }
}

export const equipmentData = [
  {
    title: "01 · CARDIO & CONDITIONING",
    items: [
      "Assault Bike Concept2 — 8 UNIDADES",
      "Remo Concept2 Model D — 6 UNIDADES",
      "SkiErg Concept2 — 4 UNIDADES",
      "Esteiras NordicTrack com inclinação negativa",
      "Cordas de batalha 15m e 20m"
    ]
  },
  {
    title: "02 · FORÇA LIVRE",
    items: [
      "Plataformas de LPO Rogue com piso de absorção",
      "Barras olímpicas masculinas e femininas (Rogue/Eleiko)",
      "Anilhas calibradas para competição",
      "Halteres sextavados de 1kg a 50kg",
      "Kettlebells de competição (4kg a 48kg)"
    ]
  },
  {
    title: "03 · MÁQUINAS",
    items: [
      "Linha Hammer Strength plate-loaded",
      "Leg Press 45º linear industrial",
      "Hack Machine articulado",
      "Cross Over com polias ajustáveis em alumínio",
      "Máquinas isoladas com biometria angular"
    ]
  },
  {
    title: "04 · FUNCIONAL & MOBILITY",
    items: [
      "Rig central modular com 12 estações de pull-up",
      "Argolas olímpicas ajustáveis",
      "Caixas pliométricas de madeira reforçada",
      "Kits completos de bandas elásticas e liberação",
      "Piso especial antiderrapante"
    ]
  }
];

export const teamData = [
  { name: "RODRIGO FARIAS", role: "Head Coach", cref: "CREF 045821-G/SP", init: "RF" },
  { name: "ANA LUÍSA", role: "Conditioning", cref: "CREF 078342-G/SP", init: "AL" },
  { name: "BRUNO T.", role: "Mobility & Rehab", cref: "CREF 091205-G/SP", init: "BT" },
  { name: "CAMILA D.", role: "Personal Trainer", cref: "CREF 063417-G/SP", init: "CD" }
];

export const faqData = [
  {
    q: "Preciso ter experiência?",
    a: "Não. Todos passam pela avaliação inicial — do iniciante ao atleta. O ponto de partida é individual."
  },
  {
    q: "Posso treinar sozinho?",
    a: "Sim. A maioria dos alunos treina de forma autônoma com planilha. Coaches estão disponíveis para dúvidas pontuais — não ficam em cima."
  },
  {
    q: "Como funciona o cancelamento?",
    a: "Avise com 30 dias. Plano encerrado no próximo ciclo. Sem multa, sem justificativa obrigatória."
  },
  {
    q: "Posso visitar antes de assinar?",
    a: "Sim — e incentivamos. Agende pelo site. Você conhece o espaço, conversa com um coach e faz uma aula experimental gratuita."
  }
];

